<?php
require_once '../includes/session_init.php';require_once '../vendor/autoload.php';require_once '../database.php';
if(empty($_SESSION['super_admin'])){http_response_code(403);exit('Acesso negado.');}$id=(int)($_GET['id']??$_GET['chat_id']??0);$tipo=$_GET['tipo']??'interno';if($id<=0||!in_array($tipo,['interno','externo'],true))exit('Atendimento inválido.');$conn=getMasterConnection();
if($tipo==='interno'){$stmt=$conn->prepare("SELECT c.*,t.nome_empresa FROM chamados_suporte c LEFT JOIN tenants t ON t.tenant_id COLLATE utf8mb4_unicode_ci=c.tenant_id COLLATE utf8mb4_unicode_ci WHERE c.id=? AND c.status='concluido'");$stmt->bind_param('i',$id);$stmt->execute();$a=$stmt->get_result()->fetch_assoc();$stmt=$conn->prepare('SELECT autor_nome AS autor,mensagem,criado_em FROM chamados_historico WHERE chamado_id=? ORDER BY criado_em,id');$stmt->bind_param('i',$id);}else{$stmt=$conn->prepare("SELECT *,nome AS usuario_nome,resolvido_em AS encerrado_em FROM suporte_login WHERE id=? AND status IN ('resolvido','fechado')");$stmt->bind_param('i',$id);$stmt->execute();$a=$stmt->get_result()->fetch_assoc();$stmt=$conn->prepare("SELECT CASE WHEN tipo='sistema' THEN 'Sistema' WHEN tipo LIKE 'resposta_%' OR tipo='suporte' THEN 'Suporte' ELSE 'Solicitante' END AS autor,mensagem,criado_em FROM suporte_historico WHERE suporte_id=? ORDER BY criado_em,id");$stmt->bind_param('i',$id);}if(!$a)exit('Atendimento não encontrado.');$stmt->execute();$msgs=$stmt->get_result();$e=fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$protocolo=$a['protocolo']?:'SEM-PROTOCOLO';
$html='<style>body{font-family:DejaVu Sans,Arial;color:#222}h1{color:#087ea4}.meta{background:#f2f5f6;padding:14px}.msg{margin:12px 0;padding:10px;border-left:3px solid #087ea4}</style><h1>Histórico de Atendimento</h1><div class="meta"><b>Protocolo:</b> '.$e($protocolo).'<br><b>Tipo:</b> '.($tipo==='interno'?'Suporte interno — assinante':'Suporte externo — não assinante').'<br><b>Solicitante:</b> '.$e($a['usuario_nome']??$a['nome']).'<br><b>Contato:</b> '.$e($a['usuario_email']??$a['email']??$a['whatsapp']??'').'<br><b>Descrição:</b> '.$e($a['descricao']??'').'</div>';foreach($msgs as $m)$html.='<div class="msg"><b>'.$e($m['autor']).'</b> — '.$e(date('d/m/Y H:i',strtotime($m['criado_em']))).'<br>'.nl2br($e($m['mensagem'])).'</div>';$pdf=new Dompdf\Dompdf();$pdf->loadHtml($html,'UTF-8');$pdf->setPaper('A4');$pdf->render();$pdf->stream('suporte_'.$protocolo.'.pdf',['Attachment'=>true]);
